// Application class
@SpringBootApplication
public class OidcClientApplication {

    public static void main(String[] args) {
        SpringApplication.run(OidcClientApplication.class, args);
    }
}

// Controller class
@RestController
public class UserController {

    @GetMapping("/login")
    public String login(HttpServletRequest request) {
        // Redirect to the OIDC provider's authorization endpoint
        return "redirect:" + oidcProvider.getAuthorizationEndpoint();
    }

    @GetMapping("/callback")
    public String callback(HttpServletRequest request) {
        // Exchange authorization code for tokens
        OidcToken token = oidcProvider.exchangeAuthorizationCodeForToken(request.getParameter("code"));

        // Parse id_token claims to create user session
        OidcIdToken idToken = token.getIdToken();
        String username = idToken.getClaim("sub");

        // Set user session
        request.getSession().setAttribute("username", username);

        // Redirect to the application home page
        return "redirect:/home";
    }
}

// OIDC provider configuration
@Configuration
public class OidcProviderConfig {

    @Value("${oidc.provider.url}")
    private String oidcProviderUrl;

    @Bean
    public OidcProvider oidcProvider() {
        return OidcProvider.builder()
                .issuer(oidcProviderUrl)
                .authorizationEndpoint(oidcProviderUrl + "/authorize")
                .tokenEndpoint(oidcProviderUrl + "/token")
                .userInfoEndpoint(oidcProviderUrl + "/userinfo")
                .build();
    }
}